const duplicates = [1, 2, 2, 3, 1, 4];
const uniqueSet = new Set(duplicates);

console.log(uniqueSet.has(2)); // true
console.log([...uniqueSet]);   // [1, 2, 3, 4]`,exercises:[{id:"set-deduplicate-list",title:"Array Cleaner Deduplicator",difficulty:"Warm-up",codeSnippet:`// Example Use Case: Instantly removing raw array duplicate values
