const merged = new Map(baseMap);
for (const [k, v] of offsetMap) {
  merged.set(k, (merged.get(k) || 0) + v);
}
// merged has key "A" with value 15`,conceptContext:"Map structures are iterable collections, meaning they expose entry, key, and value traversers which can be iterated cleanly via standard loops.",description:"Write a function `mergeInventoryMaps(mapA, mapB)` that merges two ES6 Map objects, where keys are item names and values are stock quantities. Return a new Map mapping item names to the combined sum of stock quantities.",codeTemplate:`function mergeInventoryMaps(mapA, mapB) {
