queue.push("cherry"); // ["apple", "banana", "cherry"]

// Removing the first item from array
const first = queue.shift(); // returns "apple", leaving ["banana", "cherry"]

console.log(queue); // ["banana", "cherry"]
console.log(first); // "apple"`,exercises:[{id:"ds-cart-queue",title:"Shopping Cart Queue Mutator",difficulty:"Warm-up",codeSnippet:`// Example Use Case: Managing sequential task buffers
